---@class LWonderEffectCtrl
local LWonderEffectCtrl = LxClass("LWonderEffectCtrl",nil)

function LWonderEffectCtrl:LWonderEffectCtrl()
    self._effectList = {}
end

function LWonderEffectCtrl:InitCtrl(root)
    self._effRoot = root
end

--[[
local effData =
			{
				trans = trans,
				key = ,
				resName = ,
				pos = ,
				scale = 1
			}
]]

function LWonderEffectCtrl:MakeObject(effData)
    local effectKey = effData.key
    local effectData = self._effectList[effectKey]
    local effect
    if effectData then
        effectData.effData = effData
        if effectData.isLoaded then
            self:OnEffectLoaded(effectKey)
        end
        effect = effectData.effect
    else
        effect = LDisplayEffect:New()
        effectData = {effect = effect,effData = effData}
        self._effectList[effectKey] = effectData
        local trans = effData.trans or self._effRoot
        local effectName = effData.resName

        effect:CreateEffect(trans, effectName)
        effect:SetLoadedFunction(function()
                self:OnEffectLoaded(effectKey)
            end)
        effect:StartLoadEffect()
    end

    return effect
end

function LWonderEffectCtrl:OnEffectLoaded(effectKey)

    local effectData = self._effectList[effectKey]
    if not effectData then
        return
    end

    effectData.isLoaded = true
    local effect = effectData.effect
    local effData = effectData.effData
    local dpTrans = effect:GetDisplayTrans()
    if effData.renderLayer then
        effect:SetRenderLayer(effData.renderLayer)
    end

    local parentTran = effData.trans or self._effRoot
    CS.SetParentTrans(dpTrans,parentTran)
    dpTrans.localPosition = effData.pos or Vector3.zero
    dpTrans.name = effData.resName
    local scale = effData.scale or 1
    effect:SetEffectScale(scale)

    local endFunc = effData.endFunc
    if endFunc then
        endFunc(effect)
    end
end

function LWonderEffectCtrl:Clear()
    for k,v in pairs(self._effectList) do
        local effect = v.effect
        effect:Destroy()
    end

    self._effectList = {}
end

function LWonderEffectCtrl:DestroyByKey(key)
    local effectData = self._effectList[key]
    self._effectList[key] = nil
    if not effectData then
        return
    end
    local effect = effectData.effect
    effect:Destroy()
end

function LWonderEffectCtrl:GetEffByKey(key)
    if not self._effectList then
        return
    end
    return self._effectList[key]
end

function LWonderEffectCtrl:GetEffectTransByKey(key)
    local effInfo = self:GetEffByKey(key)
    return effInfo and effInfo.effect
end

function LWonderEffectCtrl:Destroy()
    self:Clear()
end

return LWonderEffectCtrl